/**
 * Image Optimization for Vercel Deployment
 * Automatic lazy loading, responsive images, and performance optimization
 */

document.addEventListener('DOMContentLoaded', function() {
  // Optimize image loading
  optimizeImages();
  
  // Monitor network speed and adjust loading strategy
  if ('connection' in navigator) {
    const connection = navigator.connection;
    handleConnectionSpeed(connection.effectiveType);
    
    connection.addEventListener('change', function() {
      handleConnectionSpeed(connection.effectiveType);
    });
  }
});

/**
 * Optimize all images on the page
 */
function optimizeImages() {
  const images = document.querySelectorAll('img');
  
  images.forEach(img => {
    // Skip if already optimal
    if (img.loading === 'lazy' || img.loading === 'eager') {
      return;
    }
    
    // Check if image is critical (above the fold)
    const rect = img.getBoundingClientRect();
    const isVisible = rect.top < window.innerHeight + 100;
    
    if (isVisible) {
      img.loading = 'eager';
      img.decoding = 'sync';
    } else {
      img.loading = 'lazy';
      img.decoding = 'async';
    }
  });
  
  // Use Intersection Observer for additional optimization
  if ('IntersectionObserver' in window) {
    const imageObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const img = entry.target;
          
          // Apply placeholder techniques
          if (img.dataset.src) {
            img.src = img.dataset.src;
          }
          
          // Unobserve after load
          img.addEventListener('load', () => {
            imageObserver.unobserve(img);
          }, { once: true });
        }
      });
    }, {
      rootMargin: '50px 0px',
      threshold: 0.01
    });
    
    document.querySelectorAll('img').forEach(img => {
      imageObserver.observe(img);
    });
  }
}

/**
 * Adjust loading strategy based on connection speed
 */
function handleConnectionSpeed(type) {
  const images = document.querySelectorAll('img[loading="lazy"]');
  
  switch (type) {
    case '4g':
    case '5g':
      // Fast connection - use responsive images with higher quality
      images.forEach(img => {
        if (img.dataset.highRes) {
          img.srcset = img.data-highRes;
        }
      });
      break;
      
    case '3g':
    case '2g':
    case 'slow-2g':
      // Slow connection - reduce quality
      images.forEach(img => {
        if (img.dataset.lowRes) {
          img.srcset = img.dataset-lowRes;
        }
      });
      break;
  }
}

/**
 * Preload critical images for better performance
 */
function preloadCriticalImages() {
  const criticalImages = [
    'images/14_1_0cfb1ba8-1af4-4156-b7df-f726b4f476f7.png',
    'images/LUMEOR__3_-removebg-preview.png',
    'images/13.jpg'
  ];
  
  criticalImages.forEach(src => {
    const img = new Image();
    img.src = src;
  });
}

// Preload on page load
window.addEventListener('load', preloadCriticalImages);

/**
 * Request animation frame optimization for image rendering
 */
function optimizeImageRendering() {
  requestAnimationFrame(() => {
    const images = document.querySelectorAll('img[loading="lazy"]');
    images.forEach(img => {
      img.style.willChange = 'opacity';
      img.addEventListener('load', () => {
        img.style.willChange = 'auto';
      }, { once: true });
    });
  });
}

// Apply on load
window.addEventListener('load', optimizeImageRendering);


// CSS Performance: Use contain for images to isolate layout
const style = document.createElement('style');
style.textContent = `
  img {
    contain: layout style paint;
    max-width: 100%;
    height: auto;
    display: block;
  }
  
  img[loading="lazy"] {
    background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%);
    background-size: 200% 100%;
    animation: shimmer 2s infinite;
  }
  
  @keyframes shimmer {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
  }
  
  img[loading="lazy"].loaded {
    animation: none;
    background: none;
  }
`;
document.head.appendChild(style);
